void
findRangeK(	long height,
			knode *knodes,
			long knodes_elem,
			long *currKnode,
			long *offset,
			long *lastKnode,
			long *offset_2,
			int *start,
			int *end,
			int *recstart,
			int *reclength,
			int count)
{
	// process levels of the tree
	#pragma omp parallel for schedule(static)
	for(int bid = 0; bid < count; bid++){
		for(int i = 0; height > i; i++){
			// Find the index of the starting node
			int thid_start = 0;
			// The original CUDA code used thid+1 for keys access, implying keys[thid] and keys[thid+1] define a range.
			// This loop finds the first key that is greater than or equal to startD[bid].
			while(thid_start < DEFAULT_ORDER && start[bid] >= knodes[currKnode[bid]].keys[thid_start]){
				thid_start++;
			}
			// Similar to findK, the effective index for the range check is `thid_start - 1`.
			int effective_thid_start = thid_start - 1;
			if (effective_thid_start < 0) effective_thid_start = 0; // Handle case where start[bid] is smaller than the first key.
			else if (effective_thid_start >= DEFAULT_ORDER) effective_thid_start = DEFAULT_ORDER - 1; // Fallback

			if(knodes_elem > knodes[currKnode[bid]].indices[effective_thid_start]){
				offset[bid] = knodes[currKnode[bid]].indices[effective_thid_start];
			} else {
				break; // Exit inner loop if index is invalid
			}

			// Find the index of the ending node
			int thid_end = 0;
			// This loop finds the first key that is greater than or equal to endD[bid].
			while(thid_end < DEFAULT_ORDER && end[bid] >= knodes[lastKnode[bid]].keys[thid_end]){
				thid_end++;
			}
			// The effective index for the range check is `thid_end - 1`.
			int effective_thid_end = thid_end - 1;
			if (effective_thid_end < 0) effective_thid_end = 0; // Handle case where end[bid] is smaller than the first key.
			else if (effective_thid_end >= DEFAULT_ORDER) effective_thid_end = DEFAULT_ORDER - 1; // Fallback

			if(knodes_elem > knodes[lastKnode[bid]].indices[effective_thid_end]){
				offset_2[bid] = knodes[lastKnode[bid]].indices[effective_thid_end];
			} else {
				break; // Exit inner loop if index is invalid
			}

			// set for next tree level
			currKnode[bid] = offset[bid];
			lastKnode[bid] = offset_2[bid];
		}

		// process leaves
		// Find the index of the starting record
		int thid_recstart = 0;
		// The original CUDA code checked `startD[bid] == knodesD[currKnodeD[bid]].keys[thid]`
		while(thid_recstart < DEFAULT_ORDER && start[bid] != knodes[currKnode[bid]].keys[thid_recstart]){
			thid_recstart++;
		}
		if (thid_recstart < DEFAULT_ORDER) {
			recstart[bid] = knodes[currKnode[bid]].indices[thid_recstart];
		}

		// Find the index of the ending record
		int thid_reclength = 0;
		// The original CUDA code checked `endD[bid] == knodesD[lastKnodeD[bid]].keys[thid]`
		while(thid_reclength < DEFAULT_ORDER && end[bid] != knodes[lastKnode[bid]].keys[thid_reclength]){
			thid_reclength++;
		}
		if (thid_reclength < DEFAULT_ORDER) {
			reclength[bid] = knodes[lastKnode[bid]].indices[thid_reclength] - recstart[bid] + 1;
		}
	}
}

